### 2. Follow Repository 클래스

**위치**: `domain/src/main/kotlin/com/maum/backend/repository/follow/`

```kotlin
interface FollowRepository : JpaRepository<FollowEntity, String> {
    // 특정 사용자가 팔로우하는 사람들 조회
    fun findByFollowerId(followerId: String): List<FollowEntity>

    // 특정 사용자를 팔로우하는 사람들 조회
    fun findByFollowingId(followingId: String): List<FollowEntity>

    // 팔로우 여부 확인
    fun findByFollowerIdAndFollowingId(followerId: String, followingId: String): FollowEntity?

    // 활성 팔로우 조회
    fun findByFollowerIdAndStatus(followerId: String, status: Int): List<FollowEntity>
}

// QueryDSL을 사용한 복잡한 쿼리
interface CustomFollowRepository {
    fun findActiveFollows(followerId: String): List<FollowEntity>
    fun findMutualFollows(userId: String): List<FollowEntity>
}

class CustomFollowRepositoryImpl(
    private val queryFactory: JPAQueryFactory,
) : CustomFollowRepository {
    override fun findActiveFollows(followerId: String): List<FollowEntity> {
        val follow = QFollowEntity.followEntity
        return queryFactory
            .selectFrom(follow)
            .where(
                follow.followerId.eq(followerId),
                follow.status.eq(FollowStatus.ACTIVE.value),
            )
            .orderBy(follow.createdAt.desc())
            .fetch()
    }

    override fun findMutualFollows(userId: String): List<FollowEntity> {
        val follow = QFollowEntity.followEntity
        return queryFactory
            .selectFrom(follow)
            .where(
                follow.followerId.eq(userId),
                follow.status.eq(FollowStatus.ACTIVE.value),
            )
            .fetch()
    }
}
```

### 3. UserService (또는 FollowService) 클래스

**위치**: `user/src/main/kotlin/com/maum/backend/service/` 또는 `follow/src/main/kotlin/com/maum/backend/service/`

```kotlin
@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val customFollowRepository: CustomFollowRepository,
) {

    // 팔로우 메서드
    @Transactional
    fun follow(followerId: String, followingId: String): FollowEntity {
        // 1. 중복 확인
        val existing = followRepository.findByFollowerIdAndFollowingId(followerId, followingId)
        if (existing != null) {
            throw AlreadyFollowingException("Already following this user")
        }

        // 2. 자기 자신 팔로우 방지
        if (followerId == followingId) {
            throw InvalidFollowException("Cannot follow yourself")
        }

        // 3. Follow 엔티티 생성
        val follow = FollowEntity(
            followerId = followerId,
            followingId = followingId,
            status = FollowStatus.ACTIVE.value
        )

        return followRepository.save(follow)
    }

    // 언팔로우 메서드
    @Transactional
    fun unfollow(followerId: String, followingId: String) {
        val follow = followRepository.findByFollowerIdAndFollowingId(followerId, followingId)
            ?: throw FollowNotFoundException("Follow relationship not found")

        followRepository.delete(follow)
    }

    // 팔로우 목록 조회 (읽기 전용)
    @Transactional(readOnly = true)
    fun getFollowing(followerId: String): List<FollowEntity> {
        return customFollowRepository.findActiveFollows(followerId)
    }

    // 팔로워 조회 (읽기 전용)
    @Transactional(readOnly = true)
    fun getFollowers(userId: String): List<FollowEntity> {
        return followRepository.findByFollowingIdAndStatus(userId, FollowStatus.ACTIVE.value)
    }

    // 상호 팔로우 확인 (읽기 전용)
    @Transactional(readOnly = true)
    fun isMutualFollow(userId: String, otherId: String): Boolean {
        val follow1 = followRepository.findByFollowerIdAndFollowingId(userId, otherId)
        val follow2 = followRepository.findByFollowerIdAndFollowingId(otherId, userId)
        return follow1 != null && follow2 != null
    }
}

// 예외 클래스들
class AlreadyFollowingException(message: String) : Exception(message)
class FollowNotFoundException(message: String) : Exception(message)
class InvalidFollowException(message: String) : Exception(message)
```

