### 5. gRPC Service 구현 (마이크로서비스)

**위치**: `follow/src/main/kotlin/com/maum/backend/controller/`

```kotlin
@GrpcService
class FollowGrpcService(
    private val followService: FollowService,
) : FollowServiceGrpc.FollowServiceImplBase() {

    override fun followUser(
        request: FollowUserRequest,
        responseObserver: StreamObserver<FollowUserResponse>,
    ) {
        try {
            val follow = followService.follow(request.followerId, request.followingId)
            val response = FollowUserResponse.newBuilder()
                .setFollowId(follow.id)
                .setFollowerId(follow.followerId)
                .setFollowingId(follow.followingId)
                .setCreatedAt(follow.createdAt.toString())
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: AlreadyFollowingException) {
            responseObserver.onError(
                Status.ALREADY_EXISTS
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        } catch (e: InvalidFollowException) {
            responseObserver.onError(
                Status.INVALID_ARGUMENT
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Internal error")
                    .asRuntimeException()
            )
        }
    }

    override fun unfollowUser(
        request: UnfollowUserRequest,
        responseObserver: StreamObserver<UnfollowUserResponse>,
    ) {
        try {
            followService.unfollow(request.followerId, request.followingId)
            val response = UnfollowUserResponse.newBuilder()
                .setSuccess(true)
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: FollowNotFoundException) {
            responseObserver.onError(
                Status.NOT_FOUND
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Internal error")
                    .asRuntimeException()
            )
        }
    }
}
```

### 6. 테스트 파일 구조

**Service 테스트**: `follow/src/test/kotlin/com/maum/backend/service/FollowServiceTest.kt`

```kotlin
@ExtendWith(MockitoExtension::class)
class FollowServiceTest {

    @Mock
    private lateinit var followRepository: FollowRepository

    @Mock
    private lateinit var customFollowRepository: CustomFollowRepository

    @InjectMocks
    private lateinit var followService: FollowService

    @Test
    fun `should follow user successfully`() {
        // given
        val followerId = "user-1"
        val followingId = "user-2"
        `when`(followRepository.findByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(null)
        val expectedFollow = FollowEntity(
            id = "follow-1",
            followerId = followerId,
            followingId = followingId
        )
        `when`(followRepository.save(any())).thenReturn(expectedFollow)

        // when
        val result = followService.follow(followerId, followingId)

        // then
        assertThat(result.id).isEqualTo("follow-1")
        assertThat(result.followerId).isEqualTo(followerId)
        verify(followRepository).save(any())
    }

    @Test
    fun `should throw when already following`() {
        // given
        val followerId = "user-1"
        val followingId = "user-2"
        val existing = FollowEntity(followerId = followerId, followingId = followingId)
        `when`(followRepository.findByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(existing)

        // when & then
        assertThrows<AlreadyFollowingException> {
            followService.follow(followerId, followingId)
        }
    }

    @Test
    fun `should throw when following self`() {
        // given
        val userId = "user-1"
        `when`(followRepository.findByFollowerIdAndFollowingId(userId, userId))
            .thenReturn(null)

        // when & then
        assertThrows<InvalidFollowException> {
            followService.follow(userId, userId)
        }
    }

    @Test
    fun `should unfollow successfully`() {
        // given
        val followerId = "user-1"
        val followingId = "user-2"
        val follow = FollowEntity(followerId = followerId, followingId = followingId)
        `when`(followRepository.findByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(follow)

        // when
        followService.unfollow(followerId, followingId)

        // then
        verify(followRepository).delete(follow)
    }
}
```

